import React from 'react';
import { Route, BrowserRouter as Router, Routes, useNavigate } from 'react-router-dom';
import './App.css';

function App() {
  return (
    <Router>
      <div className="App">
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/heart" element={<Heart />} />
          <Route path="/lung" element={<Lung />} />
        </Routes>
      </div>
    </Router>
  );
}

function Home() {
  const navigate = useNavigate();
  return (
    <div className="home">
      <h1>Medical Prediction App</h1>
      <p>Choose a prediction type:</p>
      <button onClick={() => navigate('/heart')}>Heart Disease Prediction</button>
      <button onClick={() => navigate('/lung')}>Lung Cancer Prediction</button>
    </div>
  );
}

function Heart() {
  const navigate = useNavigate();
  const [formData, setFormData] = React.useState({
    age: '', sex: '', cp: '', trbps: '', chol: '', fbs: '', restecg: '',
    thalach: '', exang: '', oldpeak: '', slope: '', ca: '', thal: ''
  });
  const [result, setResult] = React.useState(null);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const response = await fetch('http://localhost:5000/predict-heart', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData)
      });
      const data = await response.json();
      setResult(data);
    } catch (error) {
      setResult({ error: 'Failed to get prediction' });
    }
  };

  return (
    <div className="form-container">
      <h2>Heart Disease Prediction</h2>
      <form onSubmit={handleSubmit}>
        <input name="age" placeholder="Age" value={formData.age} onChange={handleChange} required type="number" />
        <input name="sex" placeholder="Sex (0=Female, 1=Male)" value={formData.sex} onChange={handleChange} required type="number" />
        <input name="cp" placeholder="Chest Pain Type (0-3)" value={formData.cp} onChange={handleChange} required type="number" />
        <input name="trbps" placeholder="Resting Blood Pressure" value={formData.trbps} onChange={handleChange} required type="number" />
        <input name="chol" placeholder="Cholesterol" value={formData.chol} onChange={handleChange} required type="number" />
        <input name="fbs" placeholder="Fasting Blood Sugar (0/1)" value={formData.fbs} onChange={handleChange} required type="number" />
        <input name="restecg" placeholder="Resting ECG (0-2)" value={formData.restecg} onChange={handleChange} required type="number" />
        <input name="thalach" placeholder="Max Heart Rate" value={formData.thalach} onChange={handleChange} required type="number" />
        <input name="exang" placeholder="Exercise Induced Angina (0/1)" value={formData.exang} onChange={handleChange} required type="number" />
        <input name="oldpeak" placeholder="ST Depression" value={formData.oldpeak} onChange={handleChange} required type="number" step="0.1" />
        <input name="slope" placeholder="Slope (0-2)" value={formData.slope} onChange={handleChange} required type="number" />
        <input name="ca" placeholder="Number of Major Vessels (0-3)" value={formData.ca} onChange={handleChange} required type="number" />
        <input name="thal" placeholder="Thalassemia (1-3)" value={formData.thal} onChange={handleChange} required type="number" />
        <button type="submit">Predict</button>
      </form>
      {result && (
        <div className="result">
          {result.error ? <p>Error: {result.error}</p> : (
            <>
              <p>Risk Level: {result.risk_level}</p>
              <p>Confidence: {(result.confidence * 100).toFixed(2)}%</p>
            </>
          )}
        </div>
      )}
      <button onClick={() => navigate('/')}>Back</button>
    </div>
  );
}

function Lung() {
  const navigate = useNavigate();
  const [file, setFile] = React.useState(null);
  const [result, setResult] = React.useState(null);

  const handleFileChange = (e) => {
    setFile(e.target.files[0]);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!file) return;
    const formData = new FormData();
    formData.append('image', file);
    try {
      const response = await fetch('http://localhost:5000/predict-lung', {
        method: 'POST',
        body: formData
      });
      const data = await response.json();
      setResult(data);
    } catch (error) {
      setResult({ error: 'Failed to get prediction' });
    }
  };

  return (
    <div className="form-container">
      <h2>Lung Cancer Prediction</h2>
      <form onSubmit={handleSubmit}>
        <input type="file" accept="image/*" onChange={handleFileChange} required />
        <button type="submit">Predict</button>
      </form>
      {result && (
        <div className="result">
          {result.error ? <p>Error: {result.error}</p> : (
            <>
              <p>Disease: {result.disease}</p>
              <p>Confidence: {(result.confidence * 100).toFixed(2)}%</p>
            </>
          )}
        </div>
      )}
      <button onClick={() => navigate('/')}>Back</button>
    </div>
  );
}

export default App;
